31	CameraKeyframe lerp(const CameraKeyframe& p0, const CameraKeyframe& p1, float t, float t0, float t1) {
32		t = (t - t0) / (t1 - t0);
33		quat R1 = p1.R;
34	
35		// take the short path
36		if (dot(R1, p0.R) < 0.0f)  {
37			R1 = -R1;
38		}
39	
40		return {
41			normalize(slerp(p0.R, R1, t)),
42			p0.T + (p1.T - p0.T) * t,
43			p0.slice + (p1.slice - p0.slice) * t,
44			p0.scale + (p1.scale - p0.scale) * t,
45			p0.fov + (p1.fov - p0.fov) * t,
46			p0.aperture_size + (p1.aperture_size - p0.aperture_size) * t,
47			p0.timestamp + (p1.timestamp - p0.timestamp) * t,
48		};
49	}
50	
51	CameraKeyframe normalize(const CameraKeyframe& p0) {
52		CameraKeyframe result = p0;
53		result.R = normalize(result.R);
54		return result;
55	}
56	
57	CameraKeyframe spline_cm(float t, const CameraKeyframe& p0, const CameraKeyframe& p1, const CameraKeyframe& p2, const CameraKeyframe& p3) {
58		CameraKeyframe q0 = lerp(p0, p1, t, -1.f, 0.f);
59		CameraKeyframe q1 = lerp(p1, p2, t,  0.f, 1.f);
60		CameraKeyframe q2 = lerp(p2, p3, t,  1.f, 2.f);
61		CameraKeyframe r0 = lerp(q0, q1, t, -1.f, 1.f);
62		CameraKeyframe r1 = lerp(q1, q2, t,  0.f, 2.f);
63		return lerp(r0, r1, t, 0.f, 1.f);
64	}
65	
66	CameraKeyframe spline_cubic(float t, const CameraKeyframe& p0, const CameraKeyframe& p1, const CameraKeyframe& p2, const CameraKeyframe& p3) {
67		float tt = t*t;
68		float ttt = t*t*t;
69		float a = (1-t)*(1-t)*(1-t)*(1.f/6.f);
70		float b = (3.f*ttt-6.f*tt+4.f)*(1.f/6.f);
71		float c = (-3.f*ttt+3.f*tt+3.f*t+1.f)*(1.f/6.f);
72		float d = ttt*(1.f/6.f);
73		return normalize(p0 * a + p1 * b + p2 * c + p3 * d);
74	}
75	
76	CameraKeyframe spline_quadratic(float t, const CameraKeyframe& p0, const CameraKeyframe& p1, const CameraKeyframe& p2) {
77		float tt = t*t;
78		float a = (1-t)*(1-t)*0.5f;
79		float b = (-2.f*tt + 2.f*t + 1.f)*0.5f;
80		float c = tt*0.5f;
81		return normalize(p0 * a + p1 * b + p2 * c);
82	}
83	
84	CameraKeyframe spline_linear(float t, const CameraKeyframe& p0, const CameraKeyframe& p1) {
85		return normalize(p0 * (1.0f - t) + p1 * t);
86	}
