88	void to_json(json& j, const CameraKeyframe& p) {
89		j = json{
90			{"R", p.R},
91			{"T", p.T},
92			{"slice", p.slice},
93			{"scale", p.scale},
94			{"fov", p.fov},
95			{"aperture_size", p.aperture_size},
96			{"timestamp", p.timestamp},
97		};
98	}
