100	bool load_relative_to_first=false; // set to true when using a camera path that is aligned with the first training image, such that it is invariant to changes in the space of the training data
101	
102	void from_json(bool is_first, const json& j, CameraKeyframe& p, const CameraKeyframe& first, const mat4x3& ref) {
103		 if (is_first && load_relative_to_first) {
104			p.from_m(ref);
105		 } else {
106			p.R = j.at("R");
107			p.T = j.at("T");
108	
109			if (load_relative_to_first) {
110				mat4 ref4 = {ref};
111				mat4 first4 = {first.m()};
112				mat4 p4 = {p.m()};
113				p.from_m(mat4x3(ref4 * inverse(first4) * p4));
114			}
115		}
116		j.at("slice").get_to(p.slice);
117		j.at("scale").get_to(p.scale);
118		j.at("fov").get_to(p.fov);
119		if (j.contains("dof")) j.at("dof").get_to(p.aperture_size); else j.at("aperture_size").get_to(p.aperture_size);
120		if (j.contains("timestamp")) j.at("timestamp").get_to(p.timestamp); else p.timestamp = 0.f;
121	}
