123	void CameraPath::save(const fs::path& path) {
124		json j = {
125			{"loop", loop},
126			{"time", play_time},
127			{"path", keyframes},
128			{"duration_seconds", duration_seconds},
129			{"spline_order", spline_order},
130		};
131		std::ofstream f(native_string(path));
132		f << j;
133	}
