135	void CameraPath::load(const fs::path& path, const mat4x3& first_xform) {
136		std::ifstream f{native_string(path)};
137		if (!f) {
138			throw std::runtime_error{fmt::format("Camera path {} does not exist.", path.str())};
139		}
140	
141		json j;
142		f >> j;
143	
144		CameraKeyframe first;
145	
146		keyframes.clear();
147		if (j.contains("loop")) loop = j["loop"];
148		if (j.contains("time")) play_time = j["time"];
149		if (j.contains("path")) for (auto& el : j["path"]) {
150			CameraKeyframe p;
151			bool is_first = keyframes.empty();
152			from_json(is_first, el, p, first, first_xform);
153			if (is_first) {
154				first = p;
155			}
156			keyframes.push_back(p);
157		}
158	
159		duration_seconds = j.value("duration_seconds", 0.0f);
160		spline_order = j.value("spline_order", 3);
161		sanitize_keyframes();
162	
163		play_time = 0.0f;
164	
165		if (keyframes.size() >= 16) {
166			keyframe_subsampling = keyframes.size() - 1;
167			editing_kernel_type = EEditingKernel::Gaussian;
168		}
169	}
