171	void CameraPath::add_camera(
172		const mat4x3& camera,
173		float slice_plane_z,
174		float scale,
175		float fov,
176		float aperture_size,
177		float bounding_radius,
178		float timestamp
179	) {
180		int n = std::max(0, int(keyframes.size()) - 1);
181		int i = (int)ceil(play_time * (float)n + 0.001f);
182		if (i > keyframes.size()) { i = keyframes.size(); }
183		if (i < 0) i = 0;
184		keyframes.insert(keyframes.begin() + i, CameraKeyframe(camera, slice_plane_z, scale, fov, aperture_size, timestamp));
185		update_cam_from_path = false;
186		play_time = get_playtime(i);
187	
188		sanitize_keyframes();
189	}
