191	float editing_kernel(float x, EEditingKernel kernel) {
192		x = kernel == EEditingKernel::Gaussian ? x : clamp(x, -1.0f, 1.0f);
193		switch (kernel) {
194			case EEditingKernel::Gaussian: return expf(-2.0f * x * x);
195			case EEditingKernel::Quartic: return (1.0f - x*x) * (1.0f - x*x);
196			case EEditingKernel::Hat: return 1.0f - fabsf(x);
197			case EEditingKernel::Box: return x > -1.0f && x < 1.0f ? 1.0f : 0.0f;
198			case EEditingKernel::None: return fabs(x) < 0.0001f ? 1.0f : 0.0f;
199			default: throw std::runtime_error{"Unknown editing kernel"};
200		}
201	}
