203	bool CameraPath::has_valid_timestamps() const {
204		float prev_timestamp = 0.0f;
205		for (size_t i = 0; i < keyframes.size(); ++i) {
206			if (!(keyframes[i].timestamp > prev_timestamp)) {
207				return false;
208			}
209	
210			prev_timestamp = keyframes[i].timestamp;
211		}
212	
213		return true;
214	}
215	
216	void CameraPath::make_keyframe_timestamps_equidistant() {
217		for (size_t i = 0; i < keyframes.size(); ++i) {
218			keyframes[i].timestamp = (i+1) / (float)keyframes.size();
219		}
220	
221		duration_seconds = 1.0f;
222	}
223	
224	void CameraPath::sanitize_keyframes() {
225		if (has_valid_timestamps()) {
226			return;
227		}
228	
229		// Timestamps are invalid. Best effort is to equally space all frames.
230		make_keyframe_timestamps_equidistant();
231	}
232	
233	CameraPath::Pos CameraPath::get_pos(float playtime) {
234		if (keyframes.empty()) {
235			return {-1, 0.0f};
236		} else if (keyframes.size() == 1) {
237			return {0, playtime};
238		}
239	
240		float duration = loop ? keyframes.back().timestamp : keyframes[keyframes.size() - 2].timestamp;
241		playtime *= duration;
242	
243		CameraKeyframe dummy;
244		dummy.timestamp = playtime;
245	
246		// Binary search to obtain relevant keyframe in O(log(n_keyframes)) time
247		auto it = std::upper_bound(keyframes.begin(), keyframes.end(), dummy, [](const auto& a, const auto& b) {
248			return a.timestamp < b.timestamp;
249		});
250	
251		int i = clamp((int)std::distance(keyframes.begin(), it), 0, (int)keyframes.size() - (loop ? 1 : 2));
252		float prev_timestamp = i == 0 ? 0.0f : keyframes[i - 1].timestamp;
253	
254		return {
255			i,
256			(playtime - prev_timestamp) / (keyframes[i].timestamp - prev_timestamp),
257		};
258	}
