261	int CameraPath::imgui(char path_filename_buf[1024], float frame_milliseconds, const mat4x3& camera, float slice_plane_z, float scale, float fov, float aperture_size, float bounding_radius, const mat4x3& first_xform) {
262		int n = std::max(0, int(keyframes.size()) - 1);
263		int read = 0; // 1=smooth, 2=hard
264	
265		ImGui::InputText("##PathFile", path_filename_buf, 1024);
266		ImGui::SameLine();
267		static std::string camera_path_load_error_string = "";
268	
269		if (rendering) { ImGui::BeginDisabled(); }
270	
271		if (ImGui::Button("Load")) {
272			try {
273				load(path_filename_buf, first_xform);
274			} catch (const std::exception& e) {
275				ImGui::OpenPopup("Camera path load error");
276				camera_path_load_error_string = std::string{"Failed to load camera path: "} + e.what();
277			}
278		}
279	
280		if (rendering) { ImGui::EndDisabled(); }
281	
282		if (ImGui::BeginPopupModal("Camera path load error", NULL, ImGuiWindowFlags_AlwaysAutoResize)) {
283			ImGui::Text("%s", camera_path_load_error_string.c_str());
284			if (ImGui::Button("OK", ImVec2(120, 0))) {
285				ImGui::CloseCurrentPopup();
286			}
287			ImGui::EndPopup();
288		}
289	
290		if (!keyframes.empty()) {
291			ImGui::SameLine();
292			if (ImGui::Button("Save")) {
293				save(path_filename_buf);
294			}
295		}
296	
297		if (rendering) { ImGui::BeginDisabled(); }
298	
299		if (ImGui::Button("Add from cam")) {
300			add_camera(camera, slice_plane_z, scale, fov, aperture_size, bounding_radius, 0.0f);
301			make_keyframe_timestamps_equidistant();
302			read = 2;
303		}
304	
305		auto p = get_pos(play_time);
306	
307		if (!keyframes.empty()) {
308			ImGui::SameLine();
309			if (ImGui::Button("Split")) {
310				update_cam_from_path = false;
311				int i = clamp(p.kfidx + 1, 0, (int)keyframes.size());
312				keyframes.insert(keyframes.begin() + i, eval_camera_path(play_time));
313				make_keyframe_timestamps_equidistant();
314				play_time = get_playtime(i);
315				read = 2;
316			}
317			ImGui::SameLine();
318	
319			int i = p.kfidx;
320			if (!loop) {
321				i += (int)round(p.t);
322			}
323	
324			if (ImGui::Button("|<")) { play_time = 0.f; read = 2; }
325			ImGui::SameLine();
326			if (ImGui::Button("<")) { play_time = n ? (get_playtime(i-1)+0.0001f) : 0.f; read = 2; }
327			ImGui::SameLine();
328			if (ImGui::Button(update_cam_from_path ? "Stop" : "Read")) { update_cam_from_path = !update_cam_from_path; read = 2; }
329			ImGui::SameLine();
330			if (ImGui::Button(">")) { play_time = n ? (get_playtime(i+1)+0.0001f) : 1.0f; read = 2; }
331			ImGui::SameLine();
332			if (ImGui::Button(">|")) { play_time = 1.0f; read = 2; }
333			ImGui::SameLine();
334			if (ImGui::Button("Dup")) {
335				update_cam_from_path = false;
336				keyframes.insert(keyframes.begin() + i, keyframes[i]);
337				make_keyframe_timestamps_equidistant();
338				play_time = get_playtime(i);
339				read = 2;
340			}
341			ImGui::SameLine();
342			if (ImGui::Button("Del")) {
343				update_cam_from_path = false;
344				keyframes.erase(keyframes.begin() + i);
345				make_keyframe_timestamps_equidistant();
346				play_time = get_playtime(i-1);
347				read = 2;
348			}
349			ImGui::SameLine();
350			if (ImGui::Button("Set")) {
351				keyframes[i] = CameraKeyframe(
352					camera,
353					slice_plane_z,
354					scale,
355					fov,
356					aperture_size,
357					0.0f
358				);
359				read = 2;
360				if (n) play_time = get_playtime(i);
361			}
362	
363			ImGui::Combo("Editing kernel", (int*)&editing_kernel_type, EditingKernelStr);
364			ImGui::SliderFloat("Editing kernel radius", &editing_kernel_radius, 0.001f, 10.0f, "%.4f", ImGuiSliderFlags_Logarithmic | ImGuiSliderFlags_NoRoundToFormat);
365	
366			if (ImGui::RadioButton("Translate", m_gizmo_op == ImGuizmo::TRANSLATE)) { m_gizmo_op = ImGuizmo::TRANSLATE; }
367			ImGui::SameLine();
368			if (ImGui::RadioButton("Rotate", m_gizmo_op == ImGuizmo::ROTATE)) { m_gizmo_op = ImGuizmo::ROTATE; }
369			ImGui::SameLine();
370			if (ImGui::RadioButton("Local", m_gizmo_mode == ImGuizmo::LOCAL)) { m_gizmo_mode = ImGuizmo::LOCAL; }
371			ImGui::SameLine();
372			if (ImGui::RadioButton("World", m_gizmo_mode == ImGuizmo::WORLD)) { m_gizmo_mode = ImGuizmo::WORLD; }
373			ImGui::SameLine();
374			ImGui::Checkbox("Loop path", &loop);
375	
376			ImGui::SliderInt("Spline order", &spline_order, 0, 3);
377	
378			if (ImGui::SliderFloat("Camera path time", &play_time, 0.0f, 1.0f)) { read = 1; }
379	
380			if (ImGui::Button("Start") && !keyframes.empty()) { auto_play_speed = 0.0f; play_time = 0.0f; read = 2; }
381			ImGui::SameLine();
382			if (ImGui::Button("Rev") && !keyframes.empty()) { auto_play_speed = -1.0f / keyframes.back().timestamp; }
383			ImGui::SameLine();
384			if (ImGui::Button(auto_play_speed != 0 ? "Pause" : "Play") && !keyframes.empty()) {
385				auto_play_speed = auto_play_speed == 0.0f ? (1.0f / keyframes.back().timestamp) : 0.0f;
386			}
387			ImGui::SameLine();
388			if (ImGui::Button("End") && !keyframes.empty()) { auto_play_speed = 0.0f; play_time = 1.0f; read = 2; }
389	
390			ImGui::SliderFloat("Auto play speed", &auto_play_speed, -1.0f, 1.0f);
391			if (auto_play_speed != 0.0f) {
392				float prev = play_time;
393				play_time = clamp(play_time + auto_play_speed * (frame_milliseconds / 1000.f), 0.0f, 1.0f);
394	
395				if (play_time != prev) {
396					read = 1;
397				}
398			}
399	
400			ImGui::SliderInt("Keyframe subsampling", &keyframe_subsampling, 1, max((int)keyframes.size() - 1, 1));
401	
402			ImGui::Text("Current keyframe %d/%d:", i, n+1);
