405				for (auto& k : keyframes) {
406					k.fov = keyframes[i].fov;
407					k.aperture_size = keyframes[i].aperture_size;
408					k.slice = keyframes[i].slice;
409					k.scale = keyframes[i].scale;
410				}
411			}
412	
413			if (ImGui::SliderFloat("Field of view", &keyframes[i].fov, 0.0f, 120.0f)) read = 2;
414			if (ImGui::SliderFloat("Aperture size", &keyframes[i].aperture_size, 0.0f, 0.1f)) read = 2;
415			if (ImGui::SliderFloat("Slice Z", &keyframes[i].slice, -bounding_radius, bounding_radius)) read = 2;
416			if (ImGui::SliderFloat("Scale", &keyframes[i].scale, 0.f,10.f)) read = 2;
417		}
418	
419		if (rendering) { ImGui::EndDisabled(); }
420	
421		return keyframes.empty() ? 0 : read;
