424	bool debug_project(const mat4& proj, vec3 p, ImVec2& o) {
425		vec4 ph{p.x, p.y, p.z, 1.0f};
426		vec4 pa = proj * ph;
427		if (pa.w <= 0.f) {
428			return false;
429		}
430	
431		o.x = pa.x / pa.w;
432		o.y = pa.y / pa.w;
433		return true;
434	}
